const norm = $('Normalise Input1').first().json;
const coverFile = $input.first().json;

// Build direct download URL from the Drive file ID
const coverUrl = coverFile.id
  ? `https://drive.google.com/uc?export=download&id=${coverFile.id}`
  : '';

return [{
  json: {
    ...norm,
    cover_url: coverUrl,
    cover_file_id: coverFile.id || ''
  }
}];

const item = $json;
const registry = $('Fetch Account Registry1').all().map(r => r.json);
const norm = (v) => String(v || '').toLowerCase().trim();

// Match by username only (platform comes FROM registry)
const match = registry.find(row =>
  norm(row.account_name) === norm(item.username)
);

if (!match) {
  return {
    json: {
      ...item,
      _skip: true,
      _skip_reason: `Username '${item.username}' not found in Account Registry`,
      _available: registry.map(r => r.account_name).join(', ')
    }
  };
}

// if (norm(String(match.active)) !== 'true') {
