//     json: {
//       ...item,
//       _skip: true,
//       _skip_reason: `Account '${item.username}' is inactive in registry`
//     }
//   };
// }

// Platform injected FROM registry
return {
  json: {
    ...item,
    _skip:           false,
    platform:        norm(match.platform || 'instagram'),
    ig_user_id:      match.ig_user_id      || '',
    access_token:    match.access_token    || '',
    credential_name: match.credential_name || ''
  }
};

