const d = $input.first().json;

// The parent workflow wraps data inside loop_over_items
const row = d.loop_over_items || d;

// --- SCHEDULING LOGIC ---
// Extract date and time from the input fields
const scheduleDate = (row['Post Schedule Date'] || '').trim();
const scheduleTime = (row['Post Schedule Time'] || '').trim();

let scheduledTimestamp = null;

if (scheduleDate && scheduleTime) {
  try {
    // Combine Date and Time (Assuming Format: YYYY-MM-DD and HH:mm)
    // You may need to adjust the string concatenation based on your exact sheet format
    const fullDateString = `${scheduleDate}T${scheduleTime}:00`;
    const dateObj = new Date(fullDateString);

    // Convert to Unix Timestamp in seconds for Meta API
    scheduledTimestamp = Math.floor(dateObj.getTime() / 1000);
  } catch (e) {
    scheduledTimestamp = scheduleDate; // Fallback if date parsing fails
  }
}
// ------------------------

const accountUsername = (row['Account to post'] || '').trim();
const caption = (row['Caption)'] || '').trim();
const reelUrl = (row['reel_url'] || '').trim();
const reelFolderUrl = (row['Drive link for video approval'] || '').trim();
const coverUrl = (row['cover_url'] || '').trim();

const folderIdMatch = reelFolderUrl.match(/folders\/([a-zA-Z0-9_-]+)/);
const reelFolderId = folderIdMatch ? folderIdMatch[1] : '';

return [{
  json: {
    source:               'sheet',
    source_id:            String(row.row_number || ''),
    reel_no:              String(row['Reel number'] || ''),
    client:               String(row['Client(drive folder name)'] || ''),
    account_username:     accountUsername,
    accounts:             [accountUsername],
    reel_url:             reelUrl,
    reel_folder_id:       reelFolderId,
    cover_url:  coverUrl,
    caption:              caption,
    title:                row['Concept input(optional)'] || ('Reel ' + (row['Reel number'] || '')),
    need_ai_caption:      (!caption || caption === ''),
    // Add the calculated timestamp to your output
    scheduled_publish_time: scheduledTimestamp 
  }
}];

const d = $('Set Cover URL').first().json;
return [{
  json: {
    source:         d.source,
    source_id:      d.source_id,
    reel_no:        d.reel_no,
    client:         d.client,
    accounts:       d.accounts,
    reel_url:       d.reel_url,
    cover_url:      d.cover_url,
    title:          d.title,
    final_caption:  d.caption
  }
}];

const base = $('Normalise Input1').first().json;
const captionNode = $('Message a model').first().json;

const caption = captionNode.content?.parts?.[0]?.text || '';

return [{
  json: {
    source:        base.source,
    source_id:     base.source_id,
    reel_no:       base.reel_no,
    client:        base.client,
    accounts:      base.accounts,
    reel_url:      base.reel_url,
    cover_url:     base.cover_url,
    title:         base.title,
    final_caption: caption
  }
}];

const d = $input.first().json;

// accounts is array of bare usernames e.g. ["avni"]
const accounts = Array.isArray(d.accounts)
  ? d.accounts
  : JSON.parse(d.accounts || '[]');

return accounts.map(username => {
  const trimmed = username.trim();
  return {
    json: {
      source:         d.source,
      source_id:      d.source_id,
      reel_no:        d.reel_no,
      client:         d.client,
      account:        trimmed,
      username:       trimmed,
      platform:       'unknown',   // resolved from registry below
      reel_url:       d.reel_url,
      cover_url:      d.cover_url,
      caption:        d.final_caption || d.caption || '',
      title:          d.title
    }
  };
});

// Platform resolved from registry in Resolve Account Credentials
// Pass-through unchanged
return $input.all().map(item => ({ json: item.json }));

const upstream = $('IG: Create Reel Container1').first().json;
return [{
  json: {
    upload_status: 'posted',
    platform:      'instagram',
    account:       upstream.account,
    username:      upstream.username,
    source:        upstream.source,
    source_id:     upstream.source_id,
    post_id:       $input.first().json.id || 'n/a',
    posted_at:     new Date().toISOString()
  }
}];

