const e = $input.first().json;
const runData = e.execution?.data?.resultData?.runData;
const normNode = runData?.['Normalise Input']?.[0]?.data?.main?.[0]?.[0]?.json;
return [{
  json: {
    error_message: '❌ Upload failed | Workflow: ' + e.workflow.name + ' | Node: ' + e.execution.error.node.name + ' | ' + e.execution.error.message,
    source_id:     normNode?.source_id || 'unknown',
    source:        normNode?.source    || 'unknown'
  }
}];

